# OEIS sequence: A317295

from math import comb
from sympy import isprime, primerange
def A317295(n):
    def f(x):
        s = bin(x)[-1:1:-1]
        m = x.bit_count()
        l = x.bit_length()
        c = n+isprime(m)+l
        for i in range(l):
            j = int(s[i])
            if j:
                m -= 1
                for p in primerange(m,l+1):
                    c += comb(i,p-m)
        return c
    m, k = n, f(n)
    while m != k: m, k = k, f(k)
    return m # _Chai Wah Wu_, Jun 09 2026

